def post(action, data):
    payload = json.dumps({'action': action, **data})
    r = requests.post(SCRIPT_URL, data={'payload': payload}, timeout=60)
    d = r.json()
    if not d.get('success'): raise Exception(d.get('error', 'Unknown'))
    return d.get('data')

def run():
    stays = json.loads(STAYS)

    print(f"Step 1: Deleting all HIST- rows from sheet...")
    res = post('deleteHistRows', {})
    print(f"  Deleted: {res.get('deleted',0)} rows")

    print(f"\nStep 2: Uploading {len(stays)} validated stays...")
    ok, fail = 0, 0
    for i, stay in enumerate(stays):
        try:
            post('bulkInsertStay', stay)
            ok += 1
            sys.stdout.write(f"\r  {i+1}/{len(stays)} | {ok} ok | {stay.get('checkIn','')} {str(stay.get('guestName',''))[:20]:<20}")
            sys.stdout.flush()
            time.sleep(0.4)
        except Exception as e:
            fail += 1
            print(f"\n  ERROR: {stay.get('stayId','?')}: {e}")
        if (i+1) % 25 == 0:
            time.sleep(3)

    print(f"\n\nUploaded: {ok} ok, {fail} failed")

    print(f"\nStep 3: Updating Guest Repository...")
    from collections import defaultdict
    guests = defaultdict(lambda: {'stays':[], 'nights':0})
    for s in stays:
        n = s.get('guestName','')
        if n and 'NaT' not in n:
            guests[n]['stays'].append(s)
            guests[n]['nights'] += int(s.get('nights',0) or 0)

    gok = 0
    for name, info in guests.items():
        ss = sorted(info['stays'], key=lambda x: x.get('checkIn',''))
        try:
            post('upsertGuest', {
                'name': name, 'phone': ss[0].get('phone',''), 'email': ss[0].get('email',''),
                'country': ss[0].get('country',''), 'fromCity': ss[0].get('fromCity',''),
                'firstStay': ss[0].get('checkIn',''), 'lastStay': ss[-1].get('checkIn',''),
                'totalStays': len(ss), 'totalNights': info['nights'],
            })
            gok += 1
            time.sleep(0.3)
        except: pass

    print(f"  {gok}/{len(guests)} guests updated")
    print(f"\n✅ Complete! Open portal → Villa Dashboard → 2022 or 2023")

if __name__ == '__main__':
    run()